 1	import { act, fireEvent, render, screen, waitFor } from '@testing-library/react';
 2	import * as React from 'react';
 3	
 4	import { RecordType } from '../../../model/flow-query';
 5	import { ShuffledDefaultPanels } from '../../__tests-data__/panels';
 6	import OverviewPanelsModal from '../overview-panels-modal';
 7	
 8	describe('<OverviewPanelsModal />', () => {
 9	  const props = {
10	    isModalOpen: true,
11	    setModalOpen: jest.fn(),
12	    recordType: 'flowLog' as RecordType,
13	    panels: ShuffledDefaultPanels,
14	    setPanels: jest.fn(),
15	    customIds: [],
16	    features: [],
17	    id: 'panels-modal'
18	  };
19	
20	  beforeEach(() => {
21	    jest.useFakeTimers();
22	    jest.clearAllMocks();
23	  });
24	
25	  afterEach(() => {
26	    jest.runOnlyPendingTimers();
27	    jest.useRealTimers();
28	  });
29	
30	  it('should render component', async () => {
31	    render(<OverviewPanelsModal {...props} />);
32	    await act(async () => {
33	      jest.runAllTimers();
34	    });
35	  });
36	
37	  it('should save once', async () => {
38	    render(<OverviewPanelsModal {...props} />);
39	    await act(async () => {
40	      jest.runAllTimers();
41	    });
42	
43	    const confirmButton = document.querySelector('.pf-v6-c-button.pf-m-primary') as HTMLElement;
44	    expect(confirmButton).toBeTruthy();
45	
46	    await act(async () => {
47	      fireEvent.click(confirmButton);
48	      jest.runAllTimers();
49	    });
50	    expect(props.setPanels).toHaveBeenCalledTimes(1);
51	  });
52	
53	  it('should update panels selected on save', async () => {
54	    render(<OverviewPanelsModal {...props} />);
55	    await act(async () => {
56	      jest.runAllTimers();
57	    });
58	
59	    await waitFor(() => {
60	      expect(screen.getAllByRole('checkbox').length).toBeGreaterThanOrEqual(2);
61	    });
62	
63	    const checkboxes = screen.getAllByRole('checkbox');
64	    await act(async () => {
65	      fireEvent.click(checkboxes[0]);
66	      fireEvent.click(checkboxes[1]);
67	      jest.runAllTimers();
68	    });
69	
70	    const saveButton = document.querySelector('.pf-v6-c-button.pf-m-primary') as HTMLElement;
71	    await act(async () => {
72	      fireEvent.click(saveButton);
73	      jest.runAllTimers();
74	    });
75	
76	    const updatedPanels = [...props.panels];
77	    updatedPanels[0] = { ...updatedPanels[0], isSelected: !updatedPanels[0].isSelected };
78	    updatedPanels[1] = { ...updatedPanels[1], isSelected: !updatedPanels[1].isSelected };
79	    expect(props.setPanels).toHaveBeenCalledWith(updatedPanels);
80	  });
81	});

